import{c as a,Q as r,j as o,m as l}from"./chunks/framework.DVkeSyfh.js";const u=JSON.parse('{"title":"Analyze the library","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/analyze-library.md","filePath":"user-guide/analyze-library.md","lastUpdated":null}'),i={name:"user-guide/analyze-library.md"};function t(s,e,n,d,c,h){return r(),o("div",null,[...e[0]||(e[0]=[l('<h1 id="analyze-the-library" tabindex="-1">Analyze the library <a class="header-anchor" href="#analyze-the-library" aria-label="Permalink to &quot;Analyze the library&quot;">​</a></h1><p>Audience: UI users<br> Goal: run analysis jobs from the browser UI<br> Type: how-to</p><p>Analysis jobs fill the local SQLite database with features, embeddings, labels, or classifier scores. Choose the smallest useful job for the workflow you want.</p><h2 id="controls" tabindex="-1">Controls <a class="header-anchor" href="#controls" aria-label="Permalink to &quot;Controls&quot;">​</a></h2><p>The Library panel exposes model checkboxes and job controls for:</p><ul><li>SONARA;</li><li>MAEST;</li><li>MERT;</li><li>CLAP;</li><li>CLASSIFIERS, when promoted classifier models exist.</li></ul><p>Important settings:</p><ul><li><code>Analyze limit</code>: <code>0</code> means the whole missing set for selected families.</li><li><code>Device</code>: <code>AUTO</code>, <code>CPU</code>, or <code>CUDA</code>.</li><li><code>Track batch size</code>: number of decoded tracks handled together.</li><li><code>Inference batch size</code>: MAEST/MERT/CLAP model forward-pass batch size.</li></ul><h2 id="recommended-order" tabindex="-1">Recommended order <a class="header-anchor" href="#recommended-order" aria-label="Permalink to &quot;Recommended order&quot;">​</a></h2><ol><li>Run SONARA on a small limit to unlock feature-based browsing and seed search.</li><li>Run MERT when you want seed-track audio similarity.</li><li>Run CLAP when you want text search.</li><li>Run MAEST when you want genre labels, syncopated-rhythm filtering, or classifier inputs.</li><li>Run CLASSIFIERS after promoting models from Rhythm Lab.</li></ol><h2 id="reset-behavior" tabindex="-1">Reset behavior <a class="header-anchor" href="#reset-behavior" aria-label="Permalink to &quot;Reset behavior&quot;">​</a></h2><p>Analysis reset controls remove database records for the selected family. They do not rewrite source audio files.</p><p>Classifier reset is scoped to stored classifier scores in SQLite. Recompute a classifier after retraining and promoting a new model for the same <code>classifier_key</code>.</p>',13)])])}const b=a(i,[["render",t]]);export{u as __pageData,b as default};
